content.content:
# TEC REST API: rate limit + timeout curto (sem uso público)
# Usa rewrite+break (não try_files) para que fastcgi_read_timeout 15 se aplique aqui
location ~ ^/wp-json/tribe {
    limit_req zone=cf_crawlers burst=2 nodelay;
    rewrite ^ /index.php?$args break;
    include /etc/nginx/snippets/php-fpm.conf;
    fastcgi_param HTTPS on;
    fastcgi_read_timeout 15;
    fastcgi_send_timeout 15;
}

# Security restrictions
location ~ /\.ht { deny all; }
location ~* /(?:wp-config\.php|readme\.html|license\.txt)$ { deny all; }

# ==== Hardening: rate limiting e bloqueios ====

# wp-login.php: rate limit anti-brute-force (5 req/min, burst=3)
location = /wp-login.php {
    limit_req zone=wp_login burst=3 nodelay;
    try_files $uri =404;
    include /etc/nginx/snippets/php-fpm.conf;
    fastcgi_param HTTPS on;
    fastcgi_read_timeout 60;
    fastcgi_send_timeout 60;
}

# xmlrpc.php: rate limit moderado — NÃO bloquear (WPML usa para sync multilíngue)
# burst=5 permite sync de múltiplos posts sem throttling; impede abuso em massa
location = /xmlrpc.php {
    limit_req zone=wp_login burst=5 nodelay;
    try_files $uri =404;
    include /etc/nginx/snippets/php-fpm.conf;
    fastcgi_param HTTPS on;
    fastcgi_read_timeout 60;
    fastcgi_send_timeout 60;
}

# wp-cron.php: bloquear acesso HTTP externo (cron roda via sistema PHP direto)
# O rewrite multisite (flag last) garante que /subsite/wp-cron.php também é bloqueado
location = /wp-cron.php {
    allow 127.0.0.1;
    deny all;
    try_files $uri =404;
    include /etc/nginx/snippets/php-fpm.conf;
    fastcgi_param HTTPS on;
    fastcgi_read_timeout 60;
    fastcgi_send_timeout 60;
}

# wp-admin/async-upload.php: upload de arquivos grandes (PDFs, imagens)

